package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    void testPrint() throws IOException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        StringWriter out = new StringWriter();
        Object object = null;
        CharSequence value = "test";
        int offset = 0;
        int len = value.length();
        boolean newRecord = true;

        // When
        csvFormat.print(object, value, offset, len, out, newRecord);

        // Then
        assertEquals("test", out.toString());
    }

    @Test
    void testPrintWithObject() throws IOException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        StringWriter out = new StringWriter();
        Object object = 123;
        CharSequence value = "test";
        int offset = 0;
        int len = value.length();
        boolean newRecord = false;

        // When
        csvFormat.print(object, value, offset, len, out, newRecord);

        // Then
        assertEquals(',' + "test", out.toString());
    }

    @Test
    void testPrintAndQuote() throws IOException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        StringWriter out = new StringWriter();
        Object object = 123;
        CharSequence value = "test";
        int offset = 0;
        int len = value.length();
        boolean newRecord = false;

        // When
        csvFormat.printAndQuote(object, value, offset, len, out, newRecord);

        // Then
        assertEquals("\",test\"", out.toString());
    }

    @Test
    void testPrintAndEscape() throws IOException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        StringWriter out = new StringWriter();
        CharSequence value = "te,st";
        int offset = 0;
        int len = value.length();

        // When
        csvFormat.printAndEscape(value, offset, len, out);

        // Then
        assertEquals("te\\,st", out.toString());
    }
}
